#include<bits/stdc++.h>
using namespace std;
int n,r;
bool v[1001];
int s[1001];
void dfs(int x,int y){
    if(x>r){
        for(int i=1;i<=r;i++) cout << setw(3) << s[i];
        cout<<"\n";
        return;
    }else{
        for(int i=y;i<=n;i++){
            if(!v[i]){
                s[x]=i;
                v[i]=1;
                dfs(x+1,i);v[i]=0;
            }
        }
    }
}
int main(){
    cin>>n>>r;
    dfs(1,1);
    return 0;
}
